import React from "react";
import clsx from "clsx";
export default function LoadingSpinner({ fullScreen = false, size = "md", text = "" }) {
  const sizes = { sm: "w-4 h-4", md: "w-8 h-8", lg: "w-12 h-12" };
  const spinner = (
    <div className="flex flex-col items-center gap-3">
      <div className={clsx("border-4 border-slate-200 border-t-primary-500 rounded-full animate-spin", sizes[size])} />
      {text && <p className="text-sm text-slate-500">{text}</p>}
    </div>
  );
  if (fullScreen) return <div className="fixed inset-0 flex items-center justify-center bg-white/80 z-50">{spinner}</div>;
  return <div className="flex items-center justify-center p-8">{spinner}</div>;
}
